-- =====================================================================
-- 08_backtest_v1_composite.sql — Crystal Ball Loop 2.0, Backtest v1
-- "Multi-source composite": tests whether a composite signal (F10-style
-- PWS blending proximity, velocity, review volume, search intent, social
-- attention, and commercial filters) beats the v0 baselines on the SAME
-- frozen protocol as ../docs (BACKTEST_V0) / 07_backtest_hit_rate.sql.
--
-- FROZEN, reused from v0 unchanged (validated: strategies A/B/C below
-- reproduce v0's published counts exactly — 101/13/38, 56/1/9, 132/2/17
-- at 6mo and 86/6/31, 61/2/6, 110/2/14 at 12mo):
--   * cohort: 7 Amazon US categories x 3 freeze dates, "challengers" =
--     top-100 list members in the 14d before t0, >=5 snapshots, avg
--     recent rank > 10; K = 10 picks per (category, t0)
--   * signal windows: rank 14d vs 30-44d; reviews 0-7d vs 23-37d
--   * outcome windows: t0+150..210 (6mo), t0+330..390 (12mo)
--   * metrics: survival = >=5 snapshots in window; winner = avg rank
--     <=10 (and <=20); median dRho = (-ln r_fut) - (-ln r_now)
--     NOTE (definition nuance): here the median is taken over strict
--     survivors (n_fut >= 5). v0's SQL included any row with >=1 future
--     snapshot, so its published medians differ in the 3rd decimal
--     (C 6mo: -0.186 strict vs -0.192 as published). Both reproduced.
--
-- STRUCTURE (a query SET — three sections):
--   Section 1 — search-intent extraction (F4). Run once per (t0 x
--     category) cell (a 7-category x 1-t0 run exceeds the 60s gateway
--     because of the title LIKE join). Output feeds Section 3's sdvv.
--   Section 2 — social-attention extraction (F5, volume-growth form).
--     One pass over sm_post_hashtag for all t0s. Output (after the
--     documented filter/formula) feeds Section 3's tags.
--   Section 3 — the evaluation harness: all strategies + ablation on
--     the frozen cohort, with Section 1/2 outputs inlined as VALUES
--     (the values below are the exact extraction outputs of the
--     validated 2026-07-05 run, so this file is self-contained and
--     reproducible end-to-end).
--
-- PARAMs: t0 freeze dates (t0s), category ids (cats), K/min_obs
-- (params), signal & outcome windows (obs), search-term filters
-- (length >= 8, must contain a space), social-tag filters (alphabetic,
-- length >= 5, 56d volume >= 20).
--
-- Executed & validated 2026-07-05 against epocadatalake (data edge
-- 2026-07-03: all 6mo windows complete; the 2025-07-01 12mo window is
-- provisional — 38 of 61 outcome days observed).
-- =====================================================================

-- =====================================================================
-- SECTION 1 — F4 search-intent extraction (run per t0 x category cell)
-- SDV per product = max over matched terms of
--   ( -ln(term rank in latest weekly period ending <= t0) )
-- - ( -ln(term rank in latest period ending <= t0 - 56d) )
-- Term universe: amz_search top-25k weekly terms, length >= 8 and
-- containing a space (multi-word). Match: term is a substring of the
-- lower-cased product title. PARAM :T0, :CAT_ID.
-- =====================================================================
WITH t0s(t0) AS (VALUES (date '2024-07-01')),                    -- PARAM
lists AS (SELECT l.cb_list_id FROM crystalball.list l
          WHERE l.cb_category_id = 35 AND l.cb_region_id = 1),   -- PARAM
obs AS (
  SELECT t.t0, li.cb_product_id,
    count(*)        FILTER (WHERE li.cb_stamp > t.t0 - 14 AND li.cb_stamp <= t.t0) AS n_recent,
    avg(li.cb_rank) FILTER (WHERE li.cb_stamp > t.t0 - 14 AND li.cb_stamp <= t.t0) AS r_now,
    avg(li.cb_rank) FILTER (WHERE li.cb_stamp BETWEEN t.t0 - 44 AND t.t0 - 30)     AS r_mid
  FROM crystalball.list_item li
  JOIN lists ls ON li.cb_list_id = ls.cb_list_id
  CROSS JOIN t0s t
  WHERE li.cb_stamp BETWEEN t.t0 - 44 AND t.t0
  GROUP BY 1, 2
),
chal AS (
  SELECT o.t0, o.cb_product_id, lower(tt.cb_title) AS title
  FROM obs o
  JOIN crystalball.amz_product ap ON ap.cb_product_id = o.cb_product_id
  JOIN crystalball.list_item_title tt ON tt.cb_title_id = ap.cb_title_id
  WHERE o.r_now IS NOT NULL AND o.r_mid IS NOT NULL AND o.n_recent >= 5 AND o.r_now > 10
),
pers AS (
  SELECT t.t0,
    (SELECT p.cb_period_id FROM crystalball.amz_term_period p
      WHERE p.cb_date_to <= t.t0 ORDER BY p.cb_date_to DESC LIMIT 1)      AS per_now,
    (SELECT p.cb_period_id FROM crystalball.amz_term_period p
      WHERE p.cb_date_to <= t.t0 - 56 ORDER BY p.cb_date_to DESC LIMIT 1) AS per_prev
  FROM t0s t
),
terms AS (
  SELECT pr.t0, lower(sn.cb_text) AS term,
    (-ln(sn.cb_rank::numeric)) - (-ln(sp.cb_rank::numeric)) AS sdv
  FROM pers pr
  JOIN crystalball.amz_search sn ON sn.cb_period_id = pr.per_now
  JOIN crystalball.amz_search sp ON sp.cb_period_id = pr.per_prev
   AND lower(sp.cb_text) = lower(sn.cb_text)
  WHERE length(sn.cb_text) >= 8 AND position(' ' IN sn.cb_text) > 0
)
SELECT c.cb_product_id, round(max(t.sdv)::numeric, 3) AS sdv
FROM chal c JOIN terms t ON t.t0 = c.t0 AND c.title LIKE '%' || t.term || '%'
GROUP BY 1 ORDER BY 1;

-- =====================================================================
-- SECTION 2 — F5 social-attention extraction (one pass, all t0s)
-- Volume-growth form: engagement-weighted growth requires joining the
-- 64M-row sm_post_hashtag to the 176M-row sm_user_engagement, which
-- does not fit the 60s statement gateway (no date indexes) — the
-- documented, pre-registered fallback is posting-volume growth:
--   SL_tag(t0) = ln(1 + posts published in (t0-28, t0])
--              - ln(1 + posts published in (t0-56, t0-28])
-- over hashtags followed since before t0-56, keeping alphabetic tags of
-- length >= 5 with >= 20 posts across both windows (computed from the
-- n_recent/n_prev counts this query returns). Output feeds Section 3.
-- =====================================================================
WITH t0s(t0) AS (VALUES (date '2024-07-01'), (date '2025-01-01'), (date '2025-07-01')),  -- PARAM
followed AS (
  SELECT lower(c.cb_hashtag) AS tag, c.cb_hashtag_id, min(c.cb_start_to_follow::date) AS first_follow
  FROM crystalball.sm_collection c GROUP BY 1, 2
)
SELECT t.t0, f.tag,
  count(*) FILTER (WHERE ph.cb_date_published::date > t.t0 - 28 AND ph.cb_date_published::date <= t.t0)      AS n_recent,
  count(*) FILTER (WHERE ph.cb_date_published::date > t.t0 - 56 AND ph.cb_date_published::date <= t.t0 - 28) AS n_prev
FROM crystalball.sm_post_hashtag ph
CROSS JOIN t0s t
JOIN followed f ON f.cb_hashtag_id = ph.cb_hashtag_id AND f.first_follow <= t.t0 - 56
WHERE ph.cb_date_published > t.t0 - 56 AND ph.cb_date_published <= t.t0
GROUP BY 1, 2
HAVING count(*) > 0
ORDER BY 1, 2;

-- =====================================================================
-- SECTION 3 — the v1 evaluation harness (strategies + ablation)
--
-- Signals per challenger, all strictly as of t0 (z() = z-score within
-- the (category, t0) challenger universe; NULL z-input -> 0):
--   PROX  = z(-ln r_now)                     proximity (baseline axis)
--   zV    = z(velocity)                      F1, 14d vs 30-44d
--   zLRG  = z(ln(1 + max(rev_gain, 0)))      F3, 30d review gain
--   zRAT  = z(avg rating, 14d)
--   zSDV  = z(SDV)                           F4, Section 1
--   zSL   = z(SL)                            F5, Section 2
--   zMOAT = z(ln(1+rev_now) - ln(1+median rev of r_now<=10 incumbents))
--   NEW   = 1 if amz_product.cb_first_ranking > t0 - 180
--   PB    = 1 if avg price (14d) within [p25, p75] of ALL category
--           top-100 products' prices at t0 (the price-band filter)
--
-- Strategies (10 picks per category x t0, cb_product_id tie-breaks):
--   A_bestseller     r_now ASC                        (v0 verbatim)
--   B_velocity       velocity DESC                    (v0 verbatim)
--   C_vel_reviews    velocity>0, rev_gain DESC        (v0 verbatim)
--   D_search         SDV DESC (matched products only)
--   E_social         SL DESC (matched products only)
--   F_product_proof  1.0*zLRG + 0.5*zRAT + 0.5*PROX + 0.5*NEW + 0.5*PB
--   G1..G5           composite candidates; weights PRE-REGISTERED, the
--                    winner selected on the TRAIN freeze (2024-07-01)
--                    ONLY, by 6mo top-10 wins, then survival, then
--                    median dRho, and evaluated frozen on 2025-01-01 +
--                    2025-07-01:
--     G1_balanced  .5*PROX+.5*zV+1*zLRG+.5*zSDV+.25*zSL+.25*NEW+.25*PB+.25*zMOAT
--     G2_proximity 1.5*PROX+.25*zV+.75*zLRG+.5*zSDV+.25*PB   <- WINNER (train: 4 top-10 wins)
--     G3_volume    .25*PROX+.5*zV+1.5*zLRG+.5*zSDV+.5*zMOAT
--     G4_intent    .5*PROX+.5*zV+.75*zLRG+1.5*zSDV+.5*zSL
--     G5_product   1*PROX+.5*zV+1*zLRG+.5*NEW+.5*PB+.5*zMOAT
--   abl1..abl5       the ablation ladder (unit-weight additive):
--     abl1 PROX+zV / abl2 +zSDV / abl3 +zSL / abl4 +zLRG /
--     abl5 abl4+0.5*zMOAT restricted to PB=1 (commercial filter)
--   (abl0 "baseline only" == A_bestseller: z is monotone in -ln r_now.)
--
-- Output: per strategy x freeze (ti 1/2/3) and pooled (ALL): picks,
-- 6/12mo survival, top-10/top-20 winners, median survivor dRho.
-- =====================================================================
WITH t0s(ti, t0) AS (VALUES (1, date '2024-07-01'), (2, date '2025-01-01'), (3, date '2025-07-01')),
cats(cat_id, cat_name) AS (VALUES (35,'CookwareSets'), (2,'Bakeware'), (84,'FoodStorage'),
       (11,'Gadgets'), (91,'Hydration'), (8,'Drinkware'), (925,'Candles')),
params AS (SELECT 10 AS k, 5 AS min_obs),
lists AS (SELECT c.cat_id, l.cb_list_id FROM cats c
  JOIN crystalball.list l ON l.cb_category_id = c.cat_id AND l.cb_region_id = 1),
obs AS (
  SELECT ls.cat_id, t.ti, t.t0, li.cb_product_id,
    count(*)        FILTER (WHERE li.cb_stamp > t.t0 - 14 AND li.cb_stamp <= t.t0) AS n_recent,
    avg(li.cb_rank) FILTER (WHERE li.cb_stamp > t.t0 - 14 AND li.cb_stamp <= t.t0) AS r_now,
    avg(li.cb_rank) FILTER (WHERE li.cb_stamp BETWEEN t.t0 - 44 AND t.t0 - 30)     AS r_mid,
    max(li.cb_review_count) FILTER (WHERE li.cb_stamp > t.t0 - 7 AND li.cb_stamp <= t.t0) AS rev_now,
    max(li.cb_review_count) FILTER (WHERE li.cb_stamp BETWEEN t.t0 - 37 AND t.t0 - 23)    AS rev_prev,
    avg(li.cb_rating) FILTER (WHERE li.cb_stamp > t.t0 - 14 AND li.cb_stamp <= t.t0) AS rat_now,
    avg(li.cb_price)  FILTER (WHERE li.cb_stamp > t.t0 - 14 AND li.cb_stamp <= t.t0) AS price_now,
    count(*)        FILTER (WHERE li.cb_stamp BETWEEN t.t0 + 150 AND t.t0 + 210) AS n_fut6,
    avg(li.cb_rank) FILTER (WHERE li.cb_stamp BETWEEN t.t0 + 150 AND t.t0 + 210) AS r_fut6,
    count(*)        FILTER (WHERE li.cb_stamp BETWEEN t.t0 + 330 AND t.t0 + 390) AS n_fut12,
    avg(li.cb_rank) FILTER (WHERE li.cb_stamp BETWEEN t.t0 + 330 AND t.t0 + 390) AS r_fut12
  FROM crystalball.list_item li
  JOIN lists ls ON li.cb_list_id = ls.cb_list_id
  CROSS JOIN t0s t
  WHERE li.cb_stamp BETWEEN t.t0 - 44 AND t.t0 + 390
    AND (li.cb_stamp <= t.t0 + 210 OR li.cb_stamp >= t.t0 + 330)
  GROUP BY 1, 2, 3, 4
),
catstat AS (
  SELECT cat_id, ti,
    percentile_cont(0.25) WITHIN GROUP (ORDER BY price_now) AS p25,
    percentile_cont(0.75) WITHIN GROUP (ORDER BY price_now) AS p75,
    percentile_cont(0.5)  WITHIN GROUP (ORDER BY rev_now) FILTER (WHERE r_now <= 10) AS inc_med_rev
  FROM obs WHERE r_now IS NOT NULL
  GROUP BY 1, 2
),
sdvv AS (
  SELECT c.ti, c.cat_id, u.cb_product_id, u.sdv
  FROM (VALUES
(1,2,ARRAY[1520778,1520779,1520780,1523275,1528550,1528558,1528559,1528561,1528562,1528615,1528784,1531308,1531309,1531513,1534278,1536700,1539193,1539421,1541910,1542172,1550397,1550399,1550400,1552842,1555558,1557985,1558222,1560889,1567013,1567023,1569384,1572314,1572365,1572709,1575411,1580951,1581330,1584567,1587671,1596325,1596537,1596541,1599050,1602295,1608168,1615655,1618570,1621773,1624390,1630133,1645449,1655518,1658612,1658613,1658821,1680376,1689061,1704010,1704507,1707151,1707233,1724169,1727381,1765912,1779260,1784280,1788502,1789896,1822921,1845960,1876765,1881765,1885080,1885285,1899433,1899553,1918836,1925511,1931644,1932110,1940125,1948334,1948768,1958808,1958817,1958818,1969404,1969406,1970040,1970041,1970807,1971264,1996553,1996554,1996556,1996557,1996558,1996560,1996561,1996563,1996564,1996566,1996567,1996569,1996570,1996574,1996575,1996578,1996579,1996580,1996584,1996586,1996592,1997624,1997626,1997627,1997629,1997631,1997632,1997633,1997635,1997636,1997637,1997638,1997640,1997642,1997644,1997645,1997647,1997651,1997653,1997655,1997656,1997658,1997660,1997662,1997663,1997664,1997666,1997669,1997671,1997673,1997677,1997679,1997970,1998010,2000098,2002187,2002254,2002489,2002490,2002491,2002492,2002493,2002494,2002495,2002496,2002497,2002498,2002499,2002501,2002503,2002505,2002508,2002509,2002510,2002514,2002515,2002516,2002517,2002518,2002519,2002520,2002522,2002523,2002524,2002528,2002529,2002530,2002532,2002534,2002536,2002549,2002553,2002558,2002575,2003007,2003020,2007598,2007600,2007601,2007603,2007605,2007609,2007646,2007659,2007741,2007747,2008958,2009000,2009045,2013158,2013194,2013195,2013289,2013292,2013297,2013302,2013306,2013318,2013324,2013367],ARRAY[0.5,-0.057,-0.118,0.026,0.03,-0.022,2.519,0.18,-0.091,0.032,-0.188,0.026,-0.056,0.175,0.488,0.325,-0.211,0.175,0.028,0.059,0.248,0.059,0.175,2.451,-0.112,0.027,0.916,0.022,-0.118,0.5,-0.459,0.027,0.227,0.287,0.227,0.092,0.334,0.5,0.155,0.027,0.175,0.5,-0.275,-0.073,0.5,0.5,0.136,0.5,-0