0.2329,-0.014,-0.0922,-0.0036,-0.0574,0.149,-0.1907,-0.0957,-0.0364,0.0157,0.0351,-0.1823,-0.1354,-0.1286,-0.2753,-0.0759,-0.0049,-0.0384,0.0231,-0.0417,-0.2475,-0.0141,-0.5029,-0.1508,-0.1823,-0.2719,-0.2113,-0.1366,-0.247,-0.2352,0.0481,0.1625,0.26,0.1542,-0.586,-0.1643,0.032,-0.037,-0.3403,0.1437,-0.1398,-0.1773,-0.1141,-0.452,-0.1335,0.0089,0.007,-0.2583,0.2498,-0.1687,-0.0886,0.5293,0.078,-0.3866,0.1047,-0.0662,-0.1476,-0.4002,0.0917,-0.1933,-0.0956,0.0597,0.1685,0.3642,-0.0767,-0.0321,0.1896,-0.2215,-0.0649,-0.0194,-0.1451,-0.5754,-0.2442,0.1154,-0.0278,0.0475,0.2007,0.1048,0.1262,0.0723,-0.5037,-0.48,0.136,-0.6143,-0.2683,0.0741,-0.1625,-0.3857,0.2032,0.5423,-0.2857,-0.2023,-0.1272,0.0122,-0.1022,-0.2787,0.0169,0.0311,0.069,0.0198,-0.1977,-0.0826,0.1241,-0.5754,-1.2631,0.0241,0.2374,-0.1012,-0.6842]::numeric[])
  ) AS c(ti, tgs, sls), LATERAL unnest(c.tgs, c.sls) AS u(tag, sl)
),
chal AS (
  SELECT o.*, ap.cb_first_ranking, lower(tt.cb_title) AS title,
    (-ln(o.r_now)) - (-ln(o.r_mid))                  AS velocity,
    coalesce(o.rev_now, 0) - coalesce(o.rev_prev, 0) AS rev_gain
  FROM obs o
  JOIN crystalball.amz_product ap ON ap.cb_product_id = o.cb_product_id
  JOIN crystalball.list_item_title tt ON tt.cb_title_id = ap.cb_title_id
  CROSS JOIN params p
  WHERE o.r_now IS NOT NULL AND o.r_mid IS NOT NULL AND o.n_recent >= p.min_obs AND o.r_now > 10
),
slp AS (
  SELECT c.ti, c.cat_id, c.cb_product_id, max(g.sl) AS sl
  FROM chal c JOIN tags g
    ON g.ti = c.ti AND replace(replace(c.title,' ',''),'-','') LIKE '%' || g.tag || '%'
  GROUP BY 1, 2, 3
),
sig AS (
  SELECT c.cat_id, c.ti, c.cb_product_id, c.r_now, c.velocity, c.rev_gain,
    c.n_fut6, c.r_fut6, c.n_fut12, c.r_fut12,
    (-ln(c.r_now))                  AS rho_now,
    ln(1 + greatest(c.rev_gain, 0)) AS lrg,
    c.rat_now, s.sdv, e.sl,
    ln(1 + coalesce(c.rev_now, 0)) - ln(1 + cs.inc_med_rev)     AS moat,
    CASE WHEN c.cb_first_ranking > c.t0 - 180 THEN 1 ELSE 0 END AS newf,
    CASE WHEN c.price_now BETWEEN cs.p25 AND cs.p75 THEN 1 ELSE 0 END AS pb
  FROM chal c
  JOIN catstat cs ON cs.cat_id = c.cat_id AND cs.ti = c.ti
  LEFT JOIN sdvv s ON s.ti = c.ti AND s.cat_id = c.cat_id AND s.cb_product_id = c.cb_product_id
  LEFT JOIN slp  e ON e.ti = c.ti AND e.cat_id = c.cat_id AND e.cb_product_id = c.cb_product_id
),
z AS (
  SELECT s.*,
    coalesce((rho_now - avg(rho_now) OVER w) / nullif(stddev_samp(rho_now) OVER w, 0), 0)   AS z_prox,
    coalesce((velocity - avg(velocity) OVER w) / nullif(stddev_samp(velocity) OVER w, 0), 0) AS z_v,
    coalesce((lrg - avg(lrg) OVER w) / nullif(stddev_samp(lrg) OVER w, 0), 0)               AS z_lrg,
    coalesce((rat_now - avg(rat_now) OVER w) / nullif(stddev_samp(rat_now) OVER w, 0), 0)   AS z_rat,
    coalesce((sdv - avg(sdv) OVER w) / nullif(stddev_samp(sdv) OVER w, 0), 0)               AS z_sdv,
    coalesce((sl - avg(sl) OVER w) / nullif(stddev_samp(sl) OVER w, 0), 0)                  AS z_sl,
    coalesce((moat - avg(moat) OVER w) / nullif(stddev_samp(moat) OVER w, 0), 0)            AS z_moat
  FROM sig s
  WINDOW w AS (PARTITION BY cat_id, ti)
),
scored AS (
  SELECT z.*,
    1.0*z_lrg + 0.5*z_rat + 0.5*z_prox + 0.5*newf + 0.5*pb                                        AS f_score,
    0.5*z_prox + 0.5*z_v + 1.0*z_lrg + 0.5*z_sdv + 0.25*z_sl + 0.25*newf + 0.25*pb + 0.25*z_moat  AS g1,
    1.5*z_prox + 0.25*z_v + 0.75*z_lrg + 0.5*z_sdv + 0.25*pb                                      AS g2,
    0.25*z_prox + 0.5*z_v + 1.5*z_lrg + 0.5*z_sdv + 0.5*z_moat                                    AS g3,
    0.5*z_prox + 0.5*z_v + 0.75*z_lrg + 1.5*z_sdv + 0.5*z_sl                                      AS g4,
    1.0*z_prox + 0.5*z_v + 1.0*z_lrg + 0.5*newf + 0.5*pb + 0.5*z_moat                             AS g5,
    z_prox + z_v                                                                                  AS abl1,
    z_prox + z_v + z_sdv                                                                          AS abl2,
    z_prox + z_v + z_sdv + z_sl                                                                   AS abl3,
    z_prox + z_v + z_sdv + z_sl + z_lrg                                                           AS abl4
  FROM z
),
ranked AS (
  SELECT s.*,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY r_now ASC, cb_product_id)          AS rn_a,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY velocity DESC, cb_product_id)      AS rn_b,
    row_number() OVER (PARTITION BY cat_id, ti
      ORDER BY CASE WHEN velocity > 0 THEN rev_gain END DESC NULLS LAST, cb_product_id)    AS rn_c,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY sdv DESC NULLS LAST, cb_product_id) AS rn_d,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY sl DESC NULLS LAST, cb_product_id)  AS rn_e,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY f_score DESC, cb_product_id)       AS rn_f,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY g1 DESC, cb_product_id)            AS rn_g1,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY g2 DESC, cb_product_id)            AS rn_g2,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY g3 DESC, cb_product_id)            AS rn_g3,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY g4 DESC, cb_product_id)            AS rn_g4,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY g5 DESC, cb_product_id)            AS rn_g5,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY abl1 DESC, cb_product_id)          AS rn_abl1,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY abl2 DESC, cb_product_id)          AS rn_abl2,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY abl3 DESC, cb_product_id)          AS rn_abl3,
    row_number() OVER (PARTITION BY cat_id, ti ORDER BY abl4 DESC, cb_product_id)          AS rn_abl4,
    row_number() OVER (PARTITION BY cat_id, ti
      ORDER BY CASE WHEN pb = 1 THEN abl4 + 0.5*z_moat END DESC NULLS LAST, cb_product_id) AS rn_abl5
  FROM scored s
),
strat AS (
  SELECT 'A_bestseller' AS strategy, r.* FROM ranked r, params p WHERE r.rn_a <= p.k
  UNION ALL SELECT 'B_velocity', r.* FROM ranked r, params p WHERE r.rn_b <= p.k
  UNION ALL SELECT 'C_vel_reviews', r.* FROM ranked r, params p WHERE r.rn_c <= p.k AND r.velocity > 0
  UNION ALL SELECT 'D_search', r.* FROM ranked r, params p WHERE r.rn_d <= p.k AND r.sdv IS NOT NULL
  UNION ALL SELECT 'E_social', r.* FROM ranked r, params p WHERE r.rn_e <= p.k AND r.sl IS NOT NULL
  UNION ALL SELECT 'F_product_proof', r.* FROM ranked r, params p WHERE r.rn_f <= p.k
  UNION ALL SELECT 'G1_balanced', r.* FROM ranked r, params p WHERE r.rn_g1 <= p.k
  UNION ALL SELECT 'G2_proximity', r.* FROM ranked r, params p WHERE r.rn_g2 <= p.k
  UNION ALL SELECT 'G3_volume', r.* FROM ranked r, params p WHERE r.rn_g3 <= p.k
  UNION ALL SELECT 'G4_intent', r.* FROM ranked r, params p WHERE r.rn_g4 <= p.k
  UNION ALL SELECT 'G5_product', r.* FROM ranked r, params p WHERE r.rn_g5 <= p.k
  UNION ALL SELECT 'abl1_prox_vel', r.* FROM ranked r, params p WHERE r.rn_abl1 <= p.k
  UNION ALL SELECT 'abl2_p_search', r.* FROM ranked r, params p WHERE r.rn_abl2 <= p.k
  UNION ALL SELECT 'abl3_p_social', r.* FROM ranked r, params p WHERE r.rn_abl3 <= p.k
  UNION ALL SELECT 'abl4_p_review', r.* FROM ranked r, params p WHERE r.rn_abl4 <= p.k
  UNION ALL SELECT 'abl5_commerce', r.* FROM ranked r, params p WHERE r.rn_abl5 <= p.k AND r.pb = 1
)
SELECT strategy,
  coalesce(ti::text, 'ALL') AS ti,
  count(*) AS picks,
  count(*) FILTER (WHERE n_fut6  >= 5)                    AS surv6,
  count(*) FILTER (WHERE n_fut6  >= 5 AND r_fut6  <= 10)  AS win6_10,
  count(*) FILTER (WHERE n_fut6  >= 5 AND r_fut6  <= 20)  AS win6_20,
  count(*) FILTER (WHERE n_fut12 >= 5)                    AS surv12,
  count(*) FILTER (WHERE n_fut12 >= 5 AND r_fut12 <= 10)  AS win12_10,
  count(*) FILTER (WHERE n_fut12 >= 5 AND r_fut12 <= 20)  AS win12_20,
  round((percentile_cont(0.5) WITHIN GROUP (ORDER BY ((-ln(r_fut6)) - (-ln(r_now))))
         FILTER (WHERE n_fut6 >= 5))::numeric, 3)  AS med_gain6,
  round((percentile_cont(0.5) WITHIN GROUP (ORDER BY ((-ln(r_fut12)) - (-ln(r_now))))
         FILTER (WHERE n_fut12 >= 5))::numeric, 3) AS med_gain12
FROM strat
GROUP BY GROUPING SETS ((strategy), (strategy, ti))
ORDER BY strategy, ti;
